DELETE FROM orderItems WHERE orderId IN (
  SELECT id FROM orders WHERE userId IS NULL
);

-- Delete payments related to test orders
DELETE FROM payments WHERE orderId IN (
  SELECT id FROM orders WHERE userId IS NULL
);

-- Finally delete the test orders
DELETE FROM orders WHERE userId IS NULL;

